import {
  LocalizationContext,
  ThemeContext,
  Viewer,
  Worker,
} from "@react-pdf-viewer/core"
import "@react-pdf-viewer/core/lib/styles/index.css"
import "@react-pdf-viewer/default-layout/lib/styles/index.css"
import { getFilePlugin } from "@react-pdf-viewer/get-file"

import { toolbarPlugin } from "@react-pdf-viewer/toolbar"
import { Col, Drawer, Empty, Image, Row, Space, Spin } from "antd"
import { useEffect, useState } from "react"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import { useResponsive } from "src/hooks/useResponsive"
import vi_VN from "../ModalViewPDF/vi_VN.json"

const DrawerViewPDF = ({
  open,
  onClose,
  fileUrl,
  attachmentName,
  listFiles,
  title,
  topSubFooter = () => <></>,
  subFooter = () => <></>,
  loading = false,
  placement = "right",
  width = 1024,
  height = "100vh",
}) => {
  const toolbarPluginInstance = toolbarPlugin({
    getFilePlugin: {
      fileNameGenerator: () => title || "document.pdf",
    },
  })
  const [currentTheme, setCurrentTheme] = useState("light")
  const [l10n, setL10n] = useState(vi_VN)
  const localizationContext = { l10n, setL10n }
  const themeContext = { currentTheme, setCurrentTheme }
  const [fileView, setFileView] = useState(undefined)
  const [indexFile, setIndexFile] = useState(0)
  const { Toolbar } = toolbarPluginInstance
  const { isMobile } = useResponsive()

  const getFilePluginInstance = getFilePlugin({
    fileNameGenerator: () => titleDrawer || attachmentName || "document.pdf",
  })

  useEffect(() => {
    if (listFiles) {
      setFileView(listFiles[indexFile])
    } else if (fileUrl) {
      setFileView({
        FileUrl: fileUrl,
      })
    }
  }, [open, indexFile, fileUrl, listFiles])

  const workerUrl = "/pdf.worker.min.js"

  const drawerFooter = (
    <div style={{ padding: "10px" }}>
      {isMobile}
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          gap: "8px",
          ...(isMobile && { flexDirection: "column" }),
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            flex: 1,
            ...(isMobile && { flexDirection: "column", gap: "8px" }),
          }}
        >
          {subFooter()}
        </div>
      </div>
    </div>
  )

  return (
    <Drawer
      title={title}
      placement={placement}
      width={width}
      height={height}
      open={open}
      onClose={onClose}
      closable={true}
      footer={drawerFooter}
      bodyStyle={{ padding: "24px" }}
    >
      <Row gutter={16}>
        {listFiles?.length > 1 && (
          <Col style={{ width: 160 }}>
            <Space size={16}>
              <ButtonCircle
                title="File trước"
                iconName="arrow-left-circle"
                enable={indexFile !== 0}
                onClick={() => {
                  setIndexFile(indexFile - 1)
                }}
              />
              <Space size={8}>
                {indexFile + 1}/{listFiles?.length}
              </Space>
              <ButtonCircle
                title="File sau"
                iconName="arrow-right-circle"
                enable={indexFile !== listFiles.length - 1}
                onClick={() => {
                  setIndexFile(indexFile + 1)
                }}
              />
            </Space>
          </Col>
        )}
      </Row>

      {loading ? (
        // Hiển thị loading khi đang tải PDF
        <div
          style={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            height: "500px",
            flexDirection: "column",
            gap: "16px",
            backgroundColor: "#fafafa",
            borderRadius: "8px",
            margin: "20px 0",
          }}
        >
          <Spin size="large" />
          <div
            style={{
              color: "#666",
              fontSize: "16px",
              textAlign: "center",
            }}
          >
            <div>Đang tạo file PDF...</div>
            <div style={{ fontSize: "14px", marginTop: "8px", color: "#999" }}>
              Vui lòng chờ trong giây lát
            </div>
          </div>
        </div>
      ) : fileView ? (
        <>
          {listFiles ? (
            <>
              {fileView?.FileType === 1 ? (
                <div
                  className="pdf-container"
                  style={{ padding: "0 20px 0 20px" }}
                >
                  <ThemeContext.Provider value={themeContext}>
                    <LocalizationContext.Provider value={localizationContext}>
                      <div
                        className={`rpv-core__viewer rpv-core__viewer--${currentTheme}`}
                        style={{
                          border: "1px solid rgba(0, 0, 0, 0.3)",
                          display: "flex",
                          flexDirection: "column",
                          height: "calc(100vh - 200px)", // Điều chỉnh chiều cao phù hợp với drawer
                          width: "100%",
                        }}
                      >
                        <div
                          style={{
                            alignItems: "center",
                            backgroundColor:
                              currentTheme === "dark" ? "#292929" : "#eeeeee",
                            borderBottom:
                              currentTheme === "dark"
                                ? "1px solid #000"
                                : "1px solid rgba(0, 0, 0, 0.1)",
                            display: "flex",
                            padding: ".25rem",
                          }}
                        >
                          <Toolbar />
                        </div>
                        <div
                          style={{
                            flex: 1,
                            overflow: "hidden",
                          }}
                        >
                          <Worker workerUrl={workerUrl} className="custom">
                            <Viewer
                              fileUrl={fileView?.FileUrl}
                              plugins={[
                                toolbarPluginInstance,
                                getFilePluginInstance,
                              ]}
                              transformGetDocumentParams={options => ({
                                ...options,
                                withCredentials: false,
                                httpHeaders: {
                                  ...options.httpHeaders,
                                  "Cache-Control": "no-cache",
                                },
                              })}
                            />
                          </Worker>
                        </div>
                      </div>
                    </LocalizationContext.Provider>
                  </ThemeContext.Provider>
                </div>
              ) : fileView?.FileType === 2 ? (
                <Image
                  src={fileView?.FileUrl}
                  style={{
                    height: "80vh",
                    width: "auto",
                    margin: "auto",
                    display: "flex",
                  }}
                />
              ) : (
                <div
                  onClick={() => window.open(fileView?.FileUrl)}
                  style={{
                    color: "#1677ff",
                    textDecoration: "underline",
                    padding: "12px 20px",
                    cursor: "pointer",
                  }}
                >
                  File thuộc dạng file tài liệu .docx, .xlsx,... vui lòng tải
                  xuống để xem
                </div>
              )}
            </>
          ) : (
            <div className="pdf-container" style={{ padding: "0 20px 0 20px" }}>
              <ThemeContext.Provider value={themeContext}>
                <LocalizationContext.Provider value={localizationContext}>
                  <div
                    className={`rpv-core__viewer rpv-core__viewer--${currentTheme}`}
                    style={{
                      border: "1px solid rgba(0, 0, 0, 0.3)",
                      display: "flex",
                      flexDirection: "column",
                      height: "calc(100vh - 200px)",
                      width: "100%",
                    }}
                  >
                    <div
                      style={{
                        alignItems: "center",
                        backgroundColor:
                          currentTheme === "dark" ? "#292929" : "#eeeeee",
                        borderBottom:
                          currentTheme === "dark"
                            ? "1px solid #000"
                            : "1px solid rgba(0, 0, 0, 0.1)",
                        display: "flex",
                        padding: ".25rem",
                      }}
                    >
                      <Toolbar />
                    </div>
                    <div
                      style={{
                        flex: 1,
                        overflow: "hidden",
                      }}
                    >
                      <Worker workerUrl={workerUrl} className="custom">
                        <Viewer
                          fileUrl={fileView?.FileUrl}
                          plugins={[
                            toolbarPluginInstance,
                            getFilePluginInstance,
                          ]}
                          transformGetDocumentParams={options => ({
                            ...options,
                            withCredentials: false,
                            httpHeaders: {
                              ...options.httpHeaders,
                              "Cache-Control": "no-cache",
                            },
                          })}
                        />
                      </Worker>
                    </div>
                  </div>
                </LocalizationContext.Provider>
              </ThemeContext.Provider>
            </div>
          )}
        </>
      ) : (
        <Empty description="Không có file" className="mt-50" />
      )}
    </Drawer>
  )
}

export default DrawerViewPDF
